import sys
input = sys.stdin.readline

def solve():
    x, y = map(int, input().split())
    if y >= x:
        lcm = x * y // gcd(x, y)
        print(lcm)
    else:
        print(x + y)

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

t = int(input())
